{
	"name": "rudel-monorepo",
	"private": true,
	"scripts": {
		"build": "turbo run build",
		"dev": "turbo run dev",
		"lint": "biome check .",
		"lint:fix": "biome check --write .",
		"format": "biome format --write .",
		"check-types": "turbo run check-types",
		"test": "turbo run test",
		"test:env": "doppler run --project rudel --config ci -- bun run test",
		"verify": "doppler run --project rudel --config ci -- turbo run lint check-types test build",
		"release:cli": "bun run ./scripts/release-cli.ts",
		"deploy": "turbo run build",
		"dev:local": "bash scripts/dev-local.sh",
		"infra:up": "docker compose up -d",
		"infra:down": "docker compose down"
	},
	"devDependencies": {
		"@biomejs/biome": "^2.4.0",
		"turbo": "^2.8.9",
		"typescript": "5.9.2"
	},
	"engines": {
		"node": ">=18"
	},
	"packageManager": "bun@1.3.5",
	"workspaces": [
		"apps/*",
		"packages/*"
	],
	"overrides": {
		"@chkit/core": "0.1.0-beta.7",
		"@chkit/clickhouse": "0.1.0-beta.7"
	},
	"dependencies": {
		"postgres": "^3.4.8"
	}
}

{
	"name": "rudel",
	"version": "0.1.4",
	"type": "module",
	"description": "CLI for the Coding Agent Analytics Platform rudel.ai",
	"homepage": "https://app.rudel.ai",
	"bin": {
		"rudel": "./dist/cli.js"
	},
	"files": [
		"dist",
		"README.md"
	],
	"scripts": {
		"dev": "bun run src/bin/cli.ts",
		"check-types": "tsc --noEmit",
		"build": "bun build src/bin/cli.ts --outdir dist --target bun",
		"test": "bun test"
	},
	"dependencies": {
		"@orpc/client": "^1.13.5",
		"@orpc/contract": "^1.13.5",
		"@stricli/core": "^1.2.5"
	},
	"devDependencies": {
		"@rudel/api-routes": "workspace:*",
		"@rudel/typescript-config": "workspace:*",
		"bun-types": "latest",
		"typescript": "5.9.2"
	}
}

